  describe("CLI", () => {
    it(
      "should read a JSON scenario from stdin and write {results: [...]} to stdout with exit code 0",
      () => {
        const scenario = {
          customer: { yearsWithMHPCO: 5 },
          steps: [
            {
              op: "quote",
              items: [
                {
                  type: "amulet",
                  material: "silver",
                  enchantment: 2,
                  cursed: false,
                },
              ],
            },
            {
              op: "claim",
              policy: 0,
              incident: {
                cause: "fire",
                damages: [{ itemType: "amulet", amount: 200 }],
              },
            },
          ],
        };

        const result = spawnSync("node_modules/.bin/tsx", ["src/cli.ts"], {
          input: JSON.stringify(scenario),
          encoding: "utf8",
        });

        expect(result.status).toBe(0);
        expect(JSON.parse(result.stdout)).toEqual({
          results: [{ premium: 59 }, { payout: 100, remainingCap: 1100 }],
        });
      },
      30000,
    );
    it.todo("should exit non-zero with the error on stderr and no results on stdout for an invalid scenario");
  });
});
